const animTime = 0.5
let notifRoot!: HTMLElement

export abstract class Notification {
    gone = false
    protected el!: HTMLElement

    abstract makeExt(el: HTMLElement): void

    make() {
        const el = document.createElement("li")
        el.classList.add("notif")
        this.makeExt(el)
        this.el = el
        notifRoot.appendChild(el)
        return this
    }

    remove() {
        if (this.gone) return
        const height = this.el.clientHeight
        const spacer = document.createElement("li")
        spacer.classList.add("slide-away")
        spacer.style.setProperty("--initial-height", `${height}px`)
        this.el.classList.add("removed")
        notifRoot.insertBefore(spacer, this.el)
        this.gone = true

        setTimeout(() => {
            this.el.remove()
            spacer.remove()
        }, (animTime + 0.1) * 1000)
    }
}

export class SimpleNotification extends Notification {
    readonly iconURL: string;
    readonly text: string;

    constructor(iconURL: string, text: string) {
        super();
        this.iconURL = iconURL;
        this.text = text;
    }

    makeExt(el: HTMLElement): void {
        el.classList.add("-sectioned")
        el.innerHTML = `
        <div class="-icon"><img alt="" src=""></div>
        <div class="-text"></div>
        `
        const icon = el.querySelector(".-icon img")! as HTMLImageElement
        const text = el.querySelector(".-text")! as HTMLElement
        icon.src = this.iconURL
        text.innerHTML = this.text
    }

    setText(text: string) {
        (this.el.querySelector(".-text")! as HTMLElement).innerHTML = text;
    }
}

export class ProgressNotification extends SimpleNotification {
    indeterminate = true
    progress = 0
    total: number | null = null

    constructor(iconURL: string, text: string) {
        super(iconURL, text);
    }

    makeExt(el: HTMLElement) {
        super.makeExt(el);
        el.classList.add("-progress")
        el.style.setProperty("--surface", "var(--positive-progress-bg)")
        el.style.setProperty("--progress-color", "var(--positive-progress-bar)")
        el.style.setProperty("--icon-bg", "#00000020")
    }

    update(progress: number, total: number | null): void {
        if (this.gone) return
        this.progress = progress
        this.total = total
        this.indeterminate = total === null
        const add = this.indeterminate ? "-indeterminate" : "-definite"
        const remove = this.indeterminate ? "-definite" : "-indeterminate"
        this.el.classList.add(add)
        this.el.classList.remove(remove)
        this.el.style.setProperty("--progress", progress.toString())
        this.el.style.setProperty("--total-progress", total?.toString() ?? "0")
    }
}

export function setNotificationRoot(root: HTMLElement) {
    notifRoot = root
    root.style.setProperty("--delay", `${animTime}s`)
}