function _deleteThisFile(e: MouseEvent) {
    const elem = e.currentTarget as HTMLElement
    const target = elem.parentElement!
    const targetID = target.dataset.id
    const file = workingSet.find(it => it.id === targetID)
    if (file) removeFile(file)
    target.remove()
}

function fileElement(file: TaggedFile) {
    const element = document.createElement("li")
    element.dataset.id = file.id
    element.dataset.state = file.state
    const first = file.id.split("-")[0]
    element.innerHTML = `
    <div class="-title">${file.file.name}</div>
    <div class="-input-no">${first}</div>
    <button class="-delete"><img src="${ICON_CLEAR}" alt="Delete button"></button>
    <div class="-desc">${file.description}</div>
    `
    const button = element.querySelector(".-delete")! as HTMLElement
    button.addEventListener("click", _deleteThisFile)
    return element
}

